function countDigit(d, low, high) {
    let count = 0;
    for (let i = low; i <= high; i++) {
        let num = i;
        while (num > 0) {
            if (num % 10 === d) {
                count++;
            }
            num = Math.floor(num / 10);
        }
    }
    return count;
}
```

